```typescript
// server/src/modules/identity/application/use-cases/register-user.use-case.test.ts
import { describe, it, expect, beforeEach, vi } from 'vitest'
import { RegisterUserUseCase } from './register-user.use-case'

describe('RegisterUserUseCase', () => {
  let sut: RegisterUserUseCase
  let userRepo: ReturnType<typeof mockUserRepository>

  beforeEach(() => {
    userRepo = mockUserRepository()
    sut = new RegisterUserUseCase(userRepo)
  })

  it('creates user with hashed password', async () => {
    userRepo.findByEmail.mockResolvedValue(null)
    const result = await sut.execute({ email: 'a@b.com', password: 'secret' })
    expect(result.ok).toBe(true)
    expect(userRepo.save).toHaveBeenCalledWith(
      expect.objectContaining({ email: 'a@b.com' })
    )
  })

  it('returns conflict when email already registered', async () => {
    userRepo.findByEmail.mockResolvedValue({ id: '1', email: 'a@b.com' })
    const result = await sut.execute({ email: 'a@b.com', password: 'secret' })
    expect(result.ok).toBe(false)
    expect(result.code).toBe('EMAIL_CONFLICT')
  })

  it('rejects passwords shorter than minimum length', async () => {
    userRepo.findByEmail.mockResolvedValue(null)
    const result = await sut.execute({ email: 'a@b.com', password: '123' })
    expect(result.ok).toBe(false)
    expect(result.code).toBe('VALIDATION_ERROR')
  })
})
