// server/src/modules/checkin/application/use-cases/bulk-checkin.use-case.test.ts
import { describe, it, expect, beforeEach, vi } from 'vitest'
import { BulkCheckinUseCase } from './bulk-checkin.use-case'

describe('BulkCheckinUseCase', () => {
  let sut: BulkCheckinUseCase
  let checkinRepo: ReturnType<typeof mockCheckinRepository>

  beforeEach(() => {
    checkinRepo = mockCheckinRepository()
    sut = new BulkCheckinUseCase(checkinRepo)
  })

  it('saves all checkin entries for a valid date', async () => {
    const entries = [
      { supplementId: 'creatine', dose: 5, unit: 'g' },
      { supplementId: 'whey', dose: 30, unit: 'g' },
    ]
    const result = await sut.execute({ userId: 'u1', date: '2026-06-04', entries })
    expect(result.ok).toBe(true)
    expect(checkinRepo.saveBulk).toHaveBeenCalledWith(
      expect.arrayContaining([expect.objectContaining({ supplementId: 'creatine' })])
    )
  })

  it('rejects a future date', async () => {
    const result = await sut.execute({ userId: 'u1', date: '2099-01-01', entries: [] })
    expect(result.ok).toBe(false)
    expect(result.code).toBe('INVALID_DATE')
  })

  it('rejects entries with negative dose', async () => {
    const result = await sut.execute({
      userId: 'u1',
      date: '2026-06-04',
      entries: [{ supplementId: 'creatine', dose: -5, unit: 'g' }],
    })
    expect(result.ok).toBe(false)
    expect(result.code).toBe('VALIDATION_ERROR')
  })

  it('overwrites existing entries for the same date', async () => {
    checkinRepo.findByUserAndDate.mockResolvedValue([{ supplementId: 'creatine' }])
    await sut.execute({ userId: 'u1', date: '2026-06-04', entries: [] })
    expect(checkinRepo.deleteByUserAndDate).toHaveBeenCalledWith('u1', '2026-06-04')
  })
})
