// frontend/src/features/checkin/checkin-service.test.js
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { CheckinService } from './checkin-service'

const mockApiClient = () => ({
  post: vi.fn(),
  get: vi.fn(),
})

describe('CheckinService', () => {
  let service, api

  beforeEach(() => {
    api = mockApiClient()
    service = new CheckinService(api)
  })

  it('submits bulk checkin to /api/checkins', async () => {
    api.post.mockResolvedValue({ ok: true, data: [] })
    const entries = [{ supplementId: 'creatine', dose: 5 }]
    await service.submitBulk('2026-06-04', entries)
    expect(api.post).toHaveBeenCalledWith('/api/checkins/bulk', {
      date: '2026-06-04',
      entries,
    })
  })

  it('throws when api returns non-ok response', async () => {
    api.post.mockResolvedValue({ ok: false, error: 'Server error' })
    await expect(
      service.submitBulk('2026-06-04', [])
    ).rejects.toThrow()
  })

  it('retries on network failure', async () => {
    api.post.mockRejectedValueOnce(new Error('Network'))
    api.post.mockResolvedValueOnce({ ok: true, data: [] })
    await expect(service.submitBulk('2026-06-04', [])).resolves.not.toThrow()
    expect(api.post).toHaveBeenCalledTimes(2)
  })
})
