**Gap: `frontend/src/platform/sync-queue.js`**

```javascript
// frontend/src/platform/sync-queue.test.js
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { SyncQueue } from './sync-queue'

describe('SyncQueue', () => {
  let queue, storage

  beforeEach(() => {
    storage = { get: vi.fn().mockReturnValue([]), set: vi.fn() }
    queue = new SyncQueue(storage)
  })

  it('enqueues an operation when offline', () => {
    queue.enqueue({ type: 'CHECKIN', payload: { date: '2026-06-04' } })
    expect(storage.set).toHaveBeenCalledWith(
      expect.any(String),
      expect.arrayContaining([expect.objectContaining({ type: 'CHECKIN' })])
    )
  })

  it('processes queue in FIFO order on flush', async () => {
    const processor = vi.fn().mockResolvedValue({ ok: true })
    const ops = [
      { type: 'CHECKIN', payload: { date: '2026-06-01' } },
      { type: 'CHECKIN', payload: { date: '2026-06-02' } },
    ]
    storage.get.mockReturnValue(ops)
    await queue.flush(processor)
    expect(processor).toHaveBeenNthCalledWith(1, ops[0])
    expect(processor).toHaveBeenNthCalledWith(2, ops[1])
  })

  it('retains failed items in queue after failed flush', async () => {
    const processor = vi.fn().mockRejectedValue(new Error('Network'))
    storage.get.mockReturnValue([{ type: 'CHECKIN' }])
    await queue.flush(processor)
    expect(storage.set).toHaveBeenCalledWith(
      expect.any(String),
      expect.arrayContaining([expect.objectContaining({ type: 'CHECKIN' })])
    )
  })

  it('clears queue after successful flush', async () => {
    const processor = vi.fn().mockResolvedValue({ ok: true })
    storage.get.mockReturnValue([{ type: 'CHECKIN' }])
    await queue.flush(processor)
    expect(storage.set).toHaveBeenCalledWith(expect.any(String), [])
  })
})
