```javascript
// frontend/src/platform/offline-handler.test.js
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { OfflineHandler } from './offline-handler'

describe('OfflineHandler', () => {
  let handler

  beforeEach(() => {
    handler = new OfflineHandler()
    vi.spyOn(window, 'addEventListener')
    vi.spyOn(window, 'removeEventListener')
  })

  afterEach(() => vi.restoreAllMocks())

  it('calls onOffline callback when network goes offline', () => {
    const cb = vi.fn()
    handler.onOffline(cb)
    window.dispatchEvent(new Event('offline'))
    expect(cb).toHaveBeenCalled()
  })

  it('calls onOnline callback when network is restored', () => {
    const cb = vi.fn()
    handler.onOnline(cb)
    window.dispatchEvent(new Event('online'))
    expect(cb).toHaveBeenCalled()
  })

  it('reports correct initial online status', () => {
    Object.defineProperty(navigator, 'onLine', { value: false, writable: true })
    expect(handler.isOnline()).toBe(false)
    Object.defineProperty(navigator, 'onLine', { value: true, writable: true })
    expect(handler.isOnline()).toBe(true)
  })

  it('cleans up event listeners on destroy', () => {
    handler.destroy()
    expect(window.removeEventListener).toHaveBeenCalledWith('offline', expect.any(Function))
    expect(window.removeEventListener).toHaveBeenCalledWith('online', expect.any(Function))
  })
})
