// e2e/login-errors.spec.ts
import { test, expect } from '@playwright/test'
import { LoginPage } from './pages/LoginPage'

test.describe('Login error paths', () => {
  test('shows validation error for empty form submission', async ({ page }) => {
    const login = new LoginPage(page)
    await login.goto()
    await login.submit()
    await expect(page.getByRole('alert')).toBeVisible()
  })

  test('shows error for wrong credentials', async ({ page }) => {
    const login = new LoginPage(page)
    await login.goto()
    await login.fillCredentials('wrong@email.com', 'badpassword')
    await login.submit()
    await expect(page.getByText(/credenciais|inválid/i)).toBeVisible()
  })

  test('shows error when backend is unreachable', async ({ page, context }) => {
    await context.route('**/api/auth/login', (route) => route.abort('failed'))
    const login = new LoginPage(page)
    await login.goto()
    await login.fillCredentials('test@example.com', 'password')
    await login.submit()
    await expect(page.getByRole('alert')).toBeVisible()
  })

  test('disables submit button while request is in flight', async ({ page, context }) => {
    let resolve: () => void
    await context.route('**/api/auth/login', async (route) => {
      await new Promise<void>((r) => (resolve = r))
      await route.continue()
    })
    const login = new LoginPage(page)
    await login.goto()
    await login.fillCredentials('test@example.com', 'password')
    await login.clickSubmit()
    await expect(page.getByRole('button', { name: /entrar/i })).toBeDisabled()
    resolve!()
  })
})
