import { JwtService } from './jwt-service'

describe('JwtService', () => {
  const secret = 'test-secret'
  let svc: JwtService

  beforeEach(() => { svc = new JwtService(secret) })

  it('signs and verifies a valid token', () => {
    const token = svc.sign({ userId: 'u1' })
    const payload = svc.verify(token)
    expect(payload.userId).toBe('u1')
  })

  it('throws on expired token', async () => {
    const token = svc.sign({ userId: 'u1' }, { expiresIn: '0s' })
    await new Promise((r) => setTimeout(r, 10))
    expect(() => svc.verify(token)).toThrow(/expired/i)
  })

  it('throws on tampered token', () => {
    const token = svc.sign({ userId: 'u1' })
    const tampered = token.slice(0, -5) + 'XXXXX'
    expect(() => svc.verify(tampered)).toThrow()
  })

  it('throws on token signed with different secret', () => {
    const otherSvc = new JwtService('other-secret')
    const token = otherSvc.sign({ userId: 'u1' })
    expect(() => svc.verify(token)).toThrow()
  })
})

